contracts/coinFlipper.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.31;

contract coinFlipper {
    address public owner; // ❗️БЫЛО: owner использовался в constructor/onlyOwner, но не был объявлен

    uint256 private seed = 0; // ❗️Лучше uint256 (стандартный тип для чисел в Solidity)

    string public rules = "0 - Rock | 1 - Scissors | 2 - Paper";
        constructor() payable {
        owner = msg.sender;
    }

    modifier onlyOwner() { // ❗️БЫЛО: модификатор onlyOwner использовался, но не был объявлен
        require(msg.sender == owner, "Only owner");
        _;
    }


    function Rnd(uint256 _modulus) private returns (uint256) {
        require(_modulus > 0, "modulus must be > 0"); // ✅ защита от деления по модулю 0

        seed++;

        // ❗️БЫЛО: % _modules (опечатка) -> должно быть % _modulus
        // ❗️Также Rnd на block.timestamp НЕ безопасен для настоящей "случайности" (можно манипулировать).
        return uint256(
            keccak256(abi.encodePacked(block.timestamp, msg.sender, seed))
        ) % _modulus;
    }



    function coinFlip(uint256 _side) public payable returns (uint256, uint256, string memory){
        // проверка на сумму
        // ❗️Комментарий был неверный: 1 BNB = 10^18 wei = 10^9 gwei (но msg.value в WEI!)
        // Здесь 100000 gwei = 0.0001 ETH/BNB (в EVM-сетях единицы одинаковые)
        require(msg.value <= 100000 gwei, "save your balance"); // ❗️БЫЛО: "safe" -> вероятно имелось "save" (не ошибка компиляции)
        require(msg.value > 0, "Please add your bet");

        // ❗️Это условие с msg.value*2 лучше писать как msg.value * 2 (у тебя ок)
        // В Solidity ^0.8 переполнение проверяется автоматически.
        require(address(this).balance >= msg.value * 2, "Contract has insufficient balance");

        // проверка на сторону
        // 0 - камень
        // 1 - ножницы
        // 2 - бумага
        // проверка на сторону
        require(_side == 0 || _side == 1 || _side == 2, "Side must be 0, 1 or 2");

        uint256 randomNumber = Rnd(3);

        // ничья
        if (randomNumber == _side) {
            (bool ok, ) = payable(msg.sender).call{value: msg.value}("");
            require(ok, "Refund failed");
            return (_side, randomNumber, "Draw");
        }

        // выигрыш
        if (
            (_side == 0 && randomNumber == 1) ||
            (_side == 1 && randomNumber == 2) ||
            (_side == 2 && randomNumber == 0)
        ) {
            (bool ok, ) = payable(msg.sender).call{value: msg.value * 2}("");
            require(ok, "Payout failed");
            return (_side, randomNumber, "You win");
        }

        return (_side, randomNumber, "You lose");
    }


    receive() external payable {}

    function withdraw() public onlyOwner {
        (bool ok, ) = payable(owner).call{value: address(this).balance}("");
        require(ok, "Withdraw failed");
    }
}

